package com.drawtaxi.app.utilimport android.Manifestimport android.content.Contextimport android.content.Intentimport android.content.pm.PackageManagerimport android.net.Uriimport android.os.Buildimport android.os.PowerManagerimport android.provider.Settingsimport androidx.activity.result.ActivityResultLauncherimport androidx.core.content.ContextCompat/** * Helper object to handle common permission checks and requests. * Provides both static methods and Context extension functions for convenience. */object PermissionHelper {    private val SMS_PERMISSIONS = arrayOf(        Manifest.permission.RECEIVE_SMS,        Manifest.permission.READ_SMS,        Manifest.permission.SEND_SMS    )    private val LOCATION_PERMISSIONS = arrayOf(        Manifest.permission.ACCESS_FINE_LOCATION,        Manifest.permission.ACCESS_COARSE_LOCATION    )    /**     * Checks if the app is on the battery optimization whitelist.     */    fun isIgnoringBatteryOptimizations(context: Context): Boolean {        val powerManager = context.getSystemService(Context.POWER_SERVICE) as? PowerManager        return powerManager?.isIgnoringBatteryOptimizations(context.packageName) ?: true    }    /**     * Requests the user to whitelist the app from battery optimizations.     * Note: This action is strictly regulated by Google Play policies.     */    fun requestIgnoreBatteryOptimization(context: Context) {        if (!isIgnoringBatteryOptimizations(context)) {            val intent = Intent(Settings.ACTION_REQUEST_IGNORE_BATTERY_OPTIMIZATIONS).apply {                data = Uri.parse("package:${context.packageName}")                if (context !is android.app.Activity) {                    addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)                }            }            context.startActivity(intent)        }    }    /**     * Opens the system battery optimization settings page.     */    fun openBatterySettings(context: Context) {        val intent = Intent(Settings.ACTION_IGNORE_BATTERY_OPTIMIZATION_SETTINGS).apply {            if (context !is android.app.Activity) {                addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)            }        }        context.startActivity(intent)    }    /**     * Checks if all SMS-related permissions are granted.     */    fun hasSmsPermissions(context: Context): Boolean =        hasPermissions(context, *SMS_PERMISSIONS)    /**     * Launches the request for SMS-related permissions.     */    fun requestSmsPermissions(launcher: ActivityResultLauncher<Array<String>>) {        launcher.launch(SMS_PERMISSIONS)    }    /**     * Checks if notification permission is granted (always true on API < 33).     */    fun hasNotificationPermission(context: Context): Boolean {        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {            context.hasPermission(Manifest.permission.POST_NOTIFICATIONS)        } else {            true        }    }    /**     * Launches the request for notification permission on Android 13+.     */    fun requestNotificationPermission(launcher: ActivityResultLauncher<String>) {        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {            launcher.launch(Manifest.permission.POST_NOTIFICATIONS)        }    }    /**     * Checks if location permissions (Fine and Coarse) are granted.     */    fun hasLocationPermissions(context: Context): Boolean =        hasPermissions(context, *LOCATION_PERMISSIONS)    /**     * Launches the request for location permissions.     */    fun requestLocationPermissions(launcher: ActivityResultLauncher<Array<String>>) {        launcher.launch(LOCATION_PERMISSIONS)    }    /**     * Helper to check multiple permissions at once.     */    private fun hasPermissions(context: Context, vararg permissions: String): Boolean =        permissions.all { context.hasPermission(it) }    /**     * Helper to check a single permission.     */    private fun Context.hasPermission(permission: String): Boolean =        ContextCompat.checkSelfPermission(this, permission) == PackageManager.PERMISSION_GRANTED}// --- Context Extensions for more idiomatic usage ---/** * Extension property to check battery optimization status. */val Context.isIgnoringBatteryOptimizations: Boolean    get() = PermissionHelper.isIgnoringBatteryOptimizations(this)/** * Extension function to check SMS permissions. */fun Context.hasSmsPermissions(): Boolean = PermissionHelper.hasSmsPermissions(this)/** * Extension function to check location permissions. */fun Context.hasLocationPermissions(): Boolean = PermissionHelper.hasLocationPermissions(this)/** * Extension function to check notification permission. */fun Context.hasNotificationPermission(): Boolean = PermissionHelper.hasNotificationPermission(this)